SET FOREIGN_KEY_CHECKS=0;
-- ----------------------------
-- Table structure for attacker
-- ----------------------------
DROP TABLE IF EXISTS `attacker`;
CREATE TABLE `attacker` (
  `id` int(11) NOT NULL auto_increment,
  `username` text,
  `tname` text,
  `comment` text,
  `date` text,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for frequest
-- ----------------------------
DROP TABLE IF EXISTS `frequest`;
CREATE TABLE `frequest` (
  `id` int(11) NOT NULL auto_increment,
  `requestfrom` varchar(45) default NULL,
  `requestto` varchar(45) default NULL,
  `dt` varchar(45) default NULL,
  `status` varchar(45) default NULL,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for fsearch
-- ----------------------------
DROP TABLE IF EXISTS `fsearch`;
CREATE TABLE `fsearch` (
  `id` int(11) NOT NULL auto_increment,
  `username` text,
  `keyword` text,
  `dt` text,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for retweets
-- ----------------------------
DROP TABLE IF EXISTS `retweets`;
CREATE TABLE `retweets` (
  `id` int(11) NOT NULL auto_increment,
  `tname` text,
  `tweet_by` text,
  `comment` text,
  `tweet_dt` text,
  `retweet_by` text,
  `re_comment` text,
  `retweet_dt` text,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for server
-- ----------------------------
DROP TABLE IF EXISTS `server`;
CREATE TABLE `server` (
  `name` text,
  `pass` text
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for tcomments
-- ----------------------------
DROP TABLE IF EXISTS `tcomments`;
CREATE TABLE `tcomments` (
  `id` int(11) NOT NULL auto_increment,
  `user` text,
  `tname` text,
  `comment` text,
  `dt` text,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for tsearch
-- ----------------------------
DROP TABLE IF EXISTS `tsearch`;
CREATE TABLE `tsearch` (
  `id` int(11) NOT NULL auto_increment,
  `user` text,
  `keyword` text,
  `dt` text,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for ttopic
-- ----------------------------
DROP TABLE IF EXISTS `ttopic`;
CREATE TABLE `ttopic` (
  `id` int(11) NOT NULL auto_increment,
  `tname` text,
  `description` text,
  `uses` text,
  `image` longblob,
  `dt` text,
  `user` text,
  `rank` int(20) default NULL,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for urlclick
-- ----------------------------
DROP TABLE IF EXISTS `urlclick`;
CREATE TABLE `urlclick` (
  `id` int(11) NOT NULL auto_increment,
  `username` text,
  `url_name` text,
  `used_count` int(14) default NULL,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for urls
-- ----------------------------
DROP TABLE IF EXISTS `urls`;
CREATE TABLE `urls` (
  `id` int(11) NOT NULL auto_increment,
  `url_name` text,
  `used_count` int(14) default NULL,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- ----------------------------
-- Table structure for user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user` (
  `id` int(11) NOT NULL auto_increment,
  `username` varchar(45) default NULL,
  `password` varchar(45) default NULL,
  `email` varchar(45) default NULL,
  `mobile` varchar(45) default NULL,
  `address` varchar(45) default NULL,
  `dob` varchar(45) default NULL,
  `gender` varchar(45) default NULL,
  `status` varchar(45) default NULL,
  `image` longblob,
  `user_kind` varchar(45) default NULL,
  PRIMARY KEY  (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

